import React from "react";

const styles = {
  wrapper: { display: "flex", gap: "6px", marginBottom: "20px" },
  step: {
    height: "4px",
    borderRadius: "2px",
    flex: 1,
    transition: "background 0.3s ease",
  },
};

/**
 * StepIndicator — horizontal step progress bar
 * Props: current (1-based), total
 */
export default function StepIndicator({ current, total }) {
  return (
    <div style={styles.wrapper} role="progressbar" aria-valuenow={current} aria-valuemax={total}>
      {Array.from({ length: total }, (_, i) => {
        const idx = i + 1;
        let bg = "#e0e0e0";
        if (idx < current) bg = "var(--success)";
        else if (idx === current) bg = "var(--brand)";
        return <div key={idx} style={{ ...styles.step, background: bg }} />;
      })}
    </div>
  );
}
